var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하담이 네가 밤마다 꿈을 꾼다고 들었다.","JPN":"カタン、毎晩夢を見ると聞いた。","ENG":"Ha Dam, I heard you've been dreaming every night.","TWN":"我聽說夏垣你每天晚上都會做夢。"},"stage":{"bg":"HANOK","bgm":"CUTSCEN_FOREST_LOOP","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그것은 어떤 꿈이냐?","JPN":"どんな夢なんだ？","ENG":"What kind of dreams are they?","TWN":"那是什麼樣的夢？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"살아본 적 없는 타인의 삶을 마치 제 것처럼 들여다 보며, 생과 사를 반복하는 꿈이요.","JPN":"生きたことのない他人の生が、まるで己の生のごとく映し出され……生と死を繰り返す夢だ。","ENG":"Dreams where I see the life of someone I've never been as if it were my own. I live and die, again and again.","TWN":"像親身經歷一樣，看著一個從未活過的陌生人的生活，並不斷地重複生與死。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그 꿈에선 언제나 아름다운 여인이 나타나곤 하지.","JPN":"その夢では必ず美しい女性が現れる。","ENG":"And in those dreams, there's always a beautiful woman.","TWN":"在那個夢裡，總會出現一位美麗的女人。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 여인은 매번 똑같은 모습이더냐?","JPN":"その女性は、毎回同じ姿をしていたか？","ENG":"Does she always look the same?","TWN":"那位女人每次都長得一樣嗎？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"아니. 꿈을 꿀 때마다 다른 사람이었소.","JPN":"いいや、夢のたびに違う姿をしていた。","ENG":"No. She's someone different each time.","TWN":"不。每次做夢，她都是不同的人。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"하나 닮은 것이 있다면… 여인은 날 항상 서생이라 부르더구려.","JPN":"1つ共通点があるとするなら……女性はいつも某のことを「ショウ」と呼んでいた。","ENG":"But there's one thing that stays the same… She always calls me Seosaeng.","TWN":"但有一點很像…女人總會叫我書生。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그렇다면 그건 꿈이 아닐 게다.","JPN":"ならばそれは夢ではないだろう。","ENG":"Then it's no ordinary dream.","TWN":"那樣的話，那不是夢。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"꿈이 아니라면 무엇이요?","JPN":"夢でないとするなら何なのだ？","ENG":"Then what would you call it?","TWN":"如果不是夢，那是什麼？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"지난 삶에 대한 일종의 기시감이지.","JPN":"前世に対する、ある種の既視感だ。","ENG":"A kind of deja vu.","TWN":"是一種對過往人生的既視感。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"예스러운 물건이 이상하리만치 익숙하다거나, 첫 사격훈련에서 만점을 받는 것처럼 말이야.","JPN":"古めかしいものが妙にしっくりきたり、初めての射撃訓練なのに満点を取ったりするのと同じことだ。","ENG":"Like recognizing an ancient relic you've never seen before, or landing a perfect score your first time on the range.","TWN":"就像對某件古董感到異常熟悉，或是在第一次射擊訓練就拿到滿分一樣。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"만점을 받은 건 본인의 천부적인 재능의 덕이라 생각했소만.","JPN":"満点を取ったのは、某の天賦の才ゆえと思っていたのだが。","ENG":"I assumed that was just thanks to my natural talent.","TWN":"我以為拿到滿分是我的天賦。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하하, 젊은 천재는 그런 한물 간 말투를 쓰지 않아.","JPN":"ははは、若き天才はそんな時代劇みたいな喋り方はしないものだ。","ENG":"Haha. Young prodigies don't talk like that.","TWN":"哈哈，年輕的天才可不會用那種過時的說話方式。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"네가 특출한 것은 그러한 삶을 수 십, 수 백 번 거듭해왔기 때문이지.","JPN":"お前の能力が優れているのは、そういう生を数十回、数百回重ねてきたからであろう。","ENG":"You stand out because you've lived that kind of life dozens, even hundreds of times over.","TWN":"你之所以與眾不同，是因為你已經重複過數十、數百次那樣的生活。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"명달 대장의 말씀은 이 몸뚱이에 아주 오래된 정신이라도 깃들어있단 뜻이오?","JPN":"アカタツ隊長は、この身にいにしえの魂が宿っているとでも言われるのか？","ENG":"So what you're saying is that this body houses a soul that's far older than it seems?","TWN":"明達隊長的意思是，這個身體裡寄宿著一個非常古老的靈魂嗎？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"비슷하다.","JPN":"そうだな。","ENG":"Close enough.","TWN":"差不多。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그 오래된 정신은 죽음으로도 끊어내지 못하여, 삶을 거듭할 때마다 따라붙는… 질긴 저주 같은 게야.","JPN":"その古い魂は死をもっても断ち切ることができず、生を重ねるたびにつきまとう……しつこい呪いのようなものだ。","ENG":"That old soul clings to you even in death. A curse… that sticks through every life you live.","TWN":"那個古老的靈魂，是連死亡都無法切斷，每次轉世都會跟隨的…像一個頑固的詛咒。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"나는 그것을 <color=#ffd34c>땅내림</color>이라 부른다.","JPN":"俺はそれを<color=#ffd34c>チガカリ</color>と呼んでいる。","ENG":"I call it <color=#ffd34c>Earthbound</color>.","TWN":"我稱之為<color=#ffd34c>地脈之力</color>。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"요컨대…","JPN":"つまるところ……","ENG":"If I understand correctly…","TWN":"總而言之…"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"윤회란 것이 실재하여, 본인과 같은 운명을 가진 사람이 관리국과 함께 일해왔다는 말씀이구려.","JPN":"輪廻というものは実在し、某と同じ運命を持つ者が管理局と力を合わせ働いていた、ということか。","ENG":"Reincarnation is real, and others like me have worked with the Administration before.","TWN":"輪迴是真實存在的，而擁有和我一樣命運的人，一直以來都和管理局一起工作？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Exactly.","TWN":"對。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"천재가 될 운명도 타고나는 것인지- 넌 매 생애마다 훌륭한 발명품을 만들어내었다.","JPN":"天才になる運命も生まれつきなのか、お前は毎回の人生で立派な発明品を生み出した。","ENG":"Fate seems to favor your mind. You've invented something remarkable in every life.","TWN":"或許連成為天才的命運都是注定的，你在每一次生命中都創造出優秀的發明。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"그리고 늘 마지막엔 터무니없는 이유로 죽었어. 똑같은 운명의 굴레에 갇혀 장생을 이루지 못하고 단명을 되풀이하는 게지.","JPN":"そして最後は必ず理不尽な理由で死ぬ。同じ運命の輪に囚われ長寿を全うできず、短命を繰り返すのだ。","ENG":"But every time, your story ends the same. You die for some absurd reason. A genius fated to burn out early, never escaping that loop.","TWN":"但每次最後都死於荒謬的理由。被困在同樣的命運輪迴中，無法長生，不斷地重複短命。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그런 운명을 되풀이하는 연유는 어떤 죽지 않는 호랑이가 내게 <color=#ffd34c>땅내림</color>이란 저주를 내렸기 때문이라 하셨고 말이오.","JPN":"某がそのような運命を繰り返す所以は、とある不死の虎が某に<color=#ffd34c>チガカリ</color>という呪いをかけたゆえであると言われるのだな。","ENG":"And this cycle. You said it began when some immortal Tiger laid a curse called <color=#ffd34c>Earthbound</color> upon me.","TWN":"而重複那樣命運的原因，是因為一隻不死的老虎對我施下名為<color=#ffd34c>地脈之力</color>的詛咒？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"우린 그 죽지 않는 호랑이를 <color=#ffd34c>짐승</color>이라 부르지.","JPN":"俺たちはその不死の虎を<color=#ffd34c>ケモノ</color>と呼んでいる。","ENG":"We call that immortal Tiger, <color=#ffd34c>the Beast</color>.","TWN":"我們稱那隻不死的老虎為<color=#ffd34c>野獸<color=#ffd34c>。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"관리국은 꽤 오랜 시간 <color=#ffd34c>짐승</color>을 처리하기 위해 싸워왔다. 지금도 마찬가지고.","JPN":"管理局は非常に長い年月の間、<color=#ffd34c>ケモノ</color>を始末するために戦ってきた。それは今も変わらない。","ENG":"The Administration has been fighting to eliminate <color=#ffd34c>the Beasts</color> for a long time. Even to this day.","TWN":"管理局花費很長一段時間來對付<color=#ffd34c>野獸</color>。現在也一樣。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"혹, 말씀하신 짐승이란 존재가 본인의 고향을 쑥대밭으로 만든 큰 괴물을 말하는 것이요?","JPN":"もしやケモノとは、某の故郷を襲ったあの巨体な化け物のことか？","ENG":"Are we talking about the same Beast that razed my hometown?","TWN":"你說的野獸，是指毀掉我故鄉的那個怪物嗎？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"틀렸다.","JPN":"いや。","ENG":"No.","TWN":"不是。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"인명을 해하는 재앙에 높고 낮음을 따지는 게 무슨 의미인가 싶지만, 내가 말하는 <color=#ffd34c>짐승</color>이란 놈은 그보다 훨씬 위험한 존재니라.","JPN":"人命を害する災いに高低を論じるのはどうかと思うが……<color=#ffd34c>ケモノ</color>はそいつより遥かに危険な存在だ。","ENG":"Every disaster that takes lives is tragic, sure. But this <color=#ffd34c>Beast</color> is something far worse.","TWN":"雖然說危害生命的災難沒有高低之分，但我說的<color=#ffd34c>野獸</color>，是比那危險得多的存在。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"지난 세월 이곳에 머물며, 관리국을 이끄는 강자들을 많이 보아왔소.","JPN":"ここに留まる間、管理局を率いる強者どもを多く見てきたが。","ENG":"I've met many strong individuals within the Administration.","TWN":"我在這裡待這麼多年，見過許多領導管理局的強者。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그토록 강한 관리국이 어째서 아직까지 범과 결착을 내지 못했는지, 이해가 되지 않는구려.","JPN":"あれほど強大な管理局がなぜいまだケモノとの決着をつけられずにいるのか、納得がいかん。","ENG":"If they're that capable, why haven't they taken the Tiger down?","TWN":"我無法理解，如此強大的管理局，為什麼到現在還無法和老虎做個了斷。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"범이 교활한 탓도 있겠지만, 거기엔 그럴만한 사정이 있다.","JPN":"虎が狡猾なのもあるが、これには事情がある。","ENG":"Partly because the Tiger is cunning. But more than that, there's a reason.","TWN":"雖然老虎很狡猾，但這是有原因的。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>땅내림</color>을 타고나지 않은 자는 짐승에게 생채기 하나 내지 못하기 때문이지.","JPN":"<color=#ffd34c>チガカリ</color>を受け継いでいない者は、ケモノに傷一つつけられないのだ。","ENG":"Anyone not <color=#ffd34c>Earthbound</color> can't so much as leave a scratch on <color=#ffd34c>the Beasts</color>.","TWN":"要是沒有<color=#ffd34c>地脈之力</color>的人，根本連野獸的一根寒毛也碰不到。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그 말씀은, 범을 잡을 적임자가 세상에 본인 하나뿐이란 거요?","JPN":"……それはつまり、虎を倒す適任者はこの世に某一人ということか？","ENG":"You're saying I'm the only one in the world who can kill the Tiger?","TWN":"你的意思是，世界上只有我一個人能對付老虎嗎？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"하하하! 그리 생각하는 것치곤 겁먹은 표정이 아니구나.","JPN":"ははは！　そう思っているわりに、顔はまったく怯えていないな。","ENG":"Hahaha! You're not exactly panicking at the thought, I'll give you that.","TWN":"哈哈哈！你的表情一點也不害怕呢。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"걱정 말아라. 땅내림을 타고난 건 하담이 너뿐만이 아니니까.","JPN":"心配するな。チガカリを受け継いでいるのはお前だけではない。","ENG":"Relax. You're not the only one born Earthbound.","TWN":"別擔心。擁有地脈之力的不只你一個，還有另一個。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"저 여인은…?","JPN":"あの女性は……？","ENG":"Who is she…?","TWN":"那女人是…？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"사실, 관리국이 자넬 영입하게 된 건 우연이 아니야.","JPN":"実は、管理局がお前をスカウトしたのは偶然ではない。","ENG":"Truth is, it's no coincidence the Administration brought you in.","TWN":"其實，管理局之所以招募你並非偶然。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"우리처럼 <color=#ffd34c>땅내림</color>을 타고난 사람들이 한 자리에 모인 건, 오랜 세월 엮어낸 필연과 같은 것이지.","JPN":"俺たちのように<color=#ffd34c>チガカリ</color>を受け継いだ者たちが集まったのは、長い歳月が織りなした必然だと言える。","ENG":"Those born with <color=#ffd34c>Earthbound</color> tend to find each other. It's inevitability.","TWN":"像我們這樣天生擁有<color=#ffd34c>地脈之力</color>的人聚集在同一個地方，是歷經長久歲月交織而成的必然。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그 필연이란 건… 이번 생을 논하기 전부터 이어져 오던 것인가?","JPN":"その必然とは……今回の人生が始まる前から受け継がれてきたものなのか？","ENG":"You mean this has been going on… since before we were even born?","TWN":"這個必然…是在我們這一生之前就延續下來的嗎？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"제법 긴 역사라고 할 수 있지.","JPN":"かなり長い歴史だろう。","ENG":"You could say it's a long history.","TWN":"可以說是有一段相當漫長的歷史。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"참고로 자네들 두 사람은 전생에도 아주 애틋한…","JPN":"ちなみにお前たち2人は前世でも非常に仲睦まじい……","ENG":"And by the way, you and she were very close in your previous lives…","TWN":"順帶一提，你們兩位在上一世是感情很好的…"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"명달 대장, 관리국의 윗분들이 아까부터 찾고 있다던데요?","JPN":"アカタツ隊長、管理局のお偉方が先程から隊長を探していましたよ。","ENG":"Commander Myeongdal, the Administration's higher-ups have been calling for you.","TWN":"明達隊長，管理局的高層好像從剛才就在找你？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"이런. 소집이 있다는 걸 까맣게 잊고 있었군.","JPN":"おっと、召集をかけられていたことをすっかり忘れていたな。","ENG":"Ah, right. I forgot we had a briefing.","TWN":"糟糕，我完全忘記要集合這回事。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"나는 다녀올 테니, 두 사람은 인사들 나누거라.","JPN":"俺は行ってくる。2人は先に話していてくれ。","ENG":"I'll be off. You two should introduce yourselves properly.","TWN":"我先過去，你們兩個互相認識一下吧。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"짐승을 쫓는 삼군문 별동대의 일원이 된 걸 환영해요.","JPN":"ケモノを追う三軍門別働隊の一員になったこと、歓迎します。","ENG":"Welcome to the Trivanguard Special Task Unit. We specialize in chasing the Beasts.","TWN":"歡迎成為追捕野獸的三軍門先鋒隊成員。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"연화라고 불러요.","JPN":"レンカと呼んでください。","ENG":"I am Yeonhwa.","TWN":"叫我蓮華吧。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"연화…","JPN":"レンカ……","ENG":"Yeonhwa…","TWN":"蓮華…"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"어쩐지 낯이 익구려. 마치-","JPN":"何やら見覚えのある顔だ。まるで……","ENG":"Why does that name feel so familiar? As if–","TWN":"總覺得很眼熟。就像—"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"예전에도 알고 있었던 것처럼 말인가요?","JPN":"昔からの知り合いのように、ですか？","ENG":"As if we've met before?","TWN":"像我們以前就認識一樣嗎？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"우리가 만난 적이 있었나?","JPN":"会ったことがあるのか？","ENG":"Have we?","TWN":"我們見過面嗎？"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신은 모르겠지만, 난 당신을 알아요.","JPN":"あなたは知らないでしょうけど、私はあなたのことを知っています。","ENG":"You may not remember, but I know who you are.","TWN":"你可能不記得，但我認識你。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"관리국 지휘부에서 제일 똑똑한 과학자…","JPN":"管理局指揮部でもっとも聡明な科学者……","ENG":"The smartest mind in the Administration headquarters.","TWN":"管理局指揮部裡最聰明的科學家…"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"율리아 박사님이 유전공학의 대가라면, 당신은 기계를 다루는 데 있어서 최고라고 들었거든요.","JPN":"ユリア博士が遺伝工学の権威なら、あなたは機械の扱いにおいて最高の技術者だと聞いています。","ENG":"If Dr. Yulia's the expert in genetic engineering, then you're the best there is with machines.","TWN":"聽說如果說茱莉亞博士是基因工程的權威，你就是在機器方面最頂尖的人才。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…그렇군.","JPN":"……そうか。","ENG":"…I see.","TWN":"…原來如此。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"하담이오. 편한대로 부르시게.","JPN":"カタンと申す。好きなように呼んでくれて構わない。","ENG":"The name is Ha Dam. Address me however you please.","TWN":"我叫夏垣。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"아깐 얘길 끊어서 미안해요. 명달 대장이 한창 설명해주는 것 같던데.","JPN":"さっきは話を遮ってごめんなさい。アカタツ隊長が色々説明していたようだったけど。","ENG":"Sorry for cutting in earlier. It looked like Commander Myeongdal was explaining something.","TWN":"剛才打斷你們的對話很抱歉，明達隊長好像正說到興頭上。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"괜찮소. 어차피 대번에 끝날 설명도 아니었으니.","JPN":"構わない。どうせすぐ終わるような話でもなかったゆえ。","ENG":"No need to apologize. It wasn't the kind of talk that ends quickly.","TWN":"沒關係。反正也不是三言兩語就能解釋清楚的。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"궁금한 게 있으면 저한테 맘껏 물어봐요. 이래 봬도 삼군문에선 한참 선배니까.","JPN":"気になることがあるなら私にどうぞ。こう見えてもこの三軍門では結構先輩ですからね。","ENG":"If you've got questions, feel free to ask. I've been with Trivanguard longer than most.","TWN":"有什麼想知道的，儘管問我。好歹我也是三軍門的前輩。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"묻고 싶은 것이라…","JPN":"気になること、か……","ENG":"Questions…","TWN":"想問的…"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그렇다면 그대도 혹시 전생에…","JPN":"それなら、そなたももしかして前世に……","ENG":"In that case, then in your past life–","TWN":"那麽，你上一世也…"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L49_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"내 개인적인 얘기는 빼고요.","JPN":"私個人の話は抜きで。","ENG":"Let's save the personal stories for later.","TWN":"我個人的事情就先不提。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그건, 우리가 친해진 다음에 찬찬히 알려 줄게요.","JPN":"それは、仲良くなってからゆっくり教えます。","ENG":"I'll tell you once we've gotten to know each other better.","TWN":"等我們變親近之後，我會慢慢告訴你的。"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"삼군문 별동대의 목적은 짐승이란 괴물을 사냥하는 것이라 들었소. 그리고 명달께선 짐승이 우리에게 어떤 저주를 내렸다고 하셨지.","JPN":"三軍門別働隊の目的は、「ケモノ」と呼ばれる化け物の討伐と聞いている。そしてアカタツ隊長はケモノが我らにとある呪いをかけたと言っていた。","ENG":"I heard the goal of the Trivanguard is to hunt the Beast. And Myeongdal said it cursed us with something.","TWN":"三軍門先鋒隊的目的是獵捕野獸。明達也說野獸對我們施下詛咒。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"우리가 그저 전생의 기억을 품고 윤회를 거듭할 뿐이라면, 이것을 저주라 부를 일도 없을 터. 짐승이 내린 저주가 정확히 어떤 것인지 묻고 싶구려.","JPN":"我らがただ前世の記憶を宿して輪廻を繰り返しているだけならば、これを呪いとは言うまい。ケモノがかけた呪いとは具体的に何であるか教えてくれまいか。","ENG":"If all we're doing is carrying memories into new lives, can you really call that a curse? I want to know what exactly is this curse the Beast laid upon us.","TWN":"如果我們只是單純帶著前世的記憶不斷輪迴，那這就不會被稱為詛咒。我想知道，野獸下的詛咒到底是什麼。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>기슭의 짐승</color>은 땅내림을 받은 사람의 운명에 기생해, 그 안의 가능성을 갉아먹어요.","JPN":"<color=#ffd34c>麓のケモノ</color>はチガカリを受け継いだ人の運命に寄生し、内に秘められたの可能性を蝕みます。","ENG":"<color=#ffd34c>The Ridge Beast</color> latches onto the fate of those born Earthbound. It feeds on their possibilities.","TWN":"<color=#ffd34c>山腳下的野獸</color>會寄生在擁有地脈之力天賦的人的命運上，啃食他們的可能性。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 가능성이란 건, 우리가 마땅히 누려야 할 미래와 행복을 아우르는- 삶을 값어치 있게 하는 모든 것들을 의미하죠.","JPN":"その可能性とは、私たちが享受すべき未来と幸せを含め……人生を価値あるものにするすべてを指します。","ENG":"Those possibilities include your future, your happiness… Everything that makes life worth living.","TWN":"而那份可能性，包含了我們理應擁有的未來和幸福—所有讓生命變得有價值的東西。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"삶을 값어치 있게 하는 모든 것이라.","JPN":"人生を価値あるものにするすべてか。","ENG":"Everything that makes life worth living, you say.","TWN":"讓生命變得有價值的東西。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"그 말은 마치… 내가 지금껏 겪어온 불운한 일들이 그 짐승의 탓이란 것처럼 들리는구려.","JPN":"それは……某が今まで経験してきた不幸すべて、そのケモノのせいであるように聞こえるが。","ENG":"So… all the misfortune I've suffered might've been the Beast's doing?","TWN":"這話聽起來，好像我至今為止經歷過的不幸，都是那隻野獸造成的。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이해해요. 과학자인 당신에겐 받아들이기 어려운 얘기겠죠.","JPN":"分かります。科学者であるあなたとしては受け入れがたいでしょうね。","ENG":"I get it. You're a scientist. Hard to accept something so vague.","TWN":"我理解。對你這個科學家來說，這很難接受吧。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"가능성을 빼앗긴다는 추상적인 표현 같은 건… 이론으로 증명하기 어려우니까요.","JPN":"可能性を奪われるという抽象的な表現を……理論的に証明することは難しいですから。","ENG":"Even more so when something as vague as \\"stealing possibilities\\" can't be… theoretically proven.","TWN":"像是可能性被剝奪這種抽象的表達…很難用理論來證明。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만 지난 삶에서도 그랬고, 이번 생에도 마찬가지일 거예요.","JPN":"でも、前世でもそうだったし、今生でも同じなはずです。","ENG":"But it happened in your past life, and it'll happen in this life too.","TWN":"但無論是上一世還是這一生，都會是一樣的。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"짐승이 존재하는 한, 죽음조차 끊어내지 못하는 저주에 영원히 시달리는 거죠.","JPN":"ケモノが存在する以上、死をもっても断ち切れない呪いに永遠に苦しめられます。","ENG":"As long as the Beast exists, you'll keep living under a curse that even death can't break.","TWN":"只要野獸存在，我們就永遠會受到連死亡都無法斬斷的詛咒折磨。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"관리국에 오기 전의 난…","JPN":"管理局に来る前の某は……","ENG":"Before I joined the Administration…","TWN":"在進入管理局之前，我…"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"한 차례 침식사태를 겪으며 내가 가진 소중한 것들을 잃었네.","JPN":"侵食事態を一度経験し、大切なものをすべて失った。","ENG":"I lived through a Corruption disaster and lost everything I hold dear that day.","TWN":"因為一場侵蝕事態，失去了一些珍貴的東西。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_DIFF_NULL","text":{"KOREA":"적어도 지금까진, 이것이 운명이 아니라… 단지 재수가 없었을 뿐이라 생각했소.","JPN":"少なくとも今までは、これは運命などではなく……単に己がついていないだけだと思っていた。","ENG":"Up until now, I told myself it was just bad luck… not fate.","TWN":"至少到目前為止，我一直認為這不是命運…只是單純的運氣不好。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…그러게요.","JPN":"……そうですね。","ENG":"…Right.","TWN":"…是啊。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"차라리 아무것도 몰랐다면, 과거는 과거로 묻어둔 채… 오늘을 여념 없이 살아갔겠죠.","JPN":"いっそのこと、何も知らなければ……過去は過去だと忘れて、今日を生きることができたでしょう。","ENG":"If you'd stayed unaware, you could've left the past buried… and lived in the present without looking back.","TWN":"如果什麼都不知道，或許我會將過去埋葬，專心過好今天。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"단지, 그날 재수가 없었던 것뿐이라고 믿으면서요.","JPN":"あれは単に運が悪かっただけなのだと思い込んでね。","ENG":"Believing it was all just a matter of being in the wrong place at the wrong time.","TWN":"一邊相信著，那天只是運氣不好而已。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_DIFF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"그날의 난… 그녀에게 더 이상 설명을 요구하지 않았어.","JPN":"あの日某は……彼女にそれ以上の説明を求めなかった。","ENG":"That day… I didn't press her for answers.","TWN":"那天，我沒有再追問她。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"비과학적이고 추상적인 표현이긴 하나, 그 눈 속을 들여다본 것만으로도 알 수 있었지.","JPN":"非科学的で抽象的な表現ではあるが、その目を見ただけで分かったのだ。","ENG":"It was all abstract and unscientific, but one look in her eyes told me everything I needed to know.","TWN":"雖然她的話很不科學、很抽象，但光是看著她的眼睛，我就能明白。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"우리네 두 사람이 거쳐온 삶이 크게 다르지 않다는 것을.","JPN":"我らが歩んできた人生は、とても似ているということが。","ENG":"That our lives hadn't been so different after all.","TWN":"我們倆所經歷的人生，並沒有太大的區別。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"앤디.","JPN":"アンディー。","ENG":"Andy.","TWN":"安狄。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"으음… 1분만 더…","JPN":"うう……あと1分だけ……","ENG":"Mm… just a bit longer…","TWN":"嗯…再睡一分鐘就好…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"핫?! 방금 그 목소린…?","JPN":"はっ！？　今の声は……？","ENG":"Huh?! That voice just now…!","TWN":"哈？！剛才那個聲音是…？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"사부!","JPN":"師匠！","ENG":"Master!","TWN":"師父！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"깨어났구나! 다행…","JPN":"目を覚ましたんだね！　よかった……","ENG":"You're awake! Thank–","TWN":"你醒了！太好了…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…이 아니라, 이 멍청한 사부야!","JPN":"……じゃなくて、このバカ師匠！","ENG":"…I mean, you idiot!","TWN":"…不對，你這個傻瓜師父！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그깟 침식체가 뭐라고 복수에 목숨을 걸어!","JPN":"侵食体なんかに復讐するために、なんで命を懸けるのよ！","ENG":"What were you thinking?! Risking your life for revenge?!","TWN":"區區一個侵蝕體，為什麼要為復仇賭上性命！"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그런 일이 있었지.","JPN":"そうだったな。","ENG":"Ah, right. That happened.","TWN":"事發突然。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"미안하네. 피치 못할 상황이 아니면 그 검은 쓰지 않기로 했는데… 내가 약속을 어겼군.","JPN":"すまない。やむを得ない状況でない限り、あの剣は使わないと約束していたのだが……某から破ってしまったな。","ENG":"That was reckless of me. I promised I'd never use that sword unless I had no other choice… but I broke that promise. I'm sorry.","TWN":"抱歉。我承諾過如果不是情況危急，不會使用那把劍…我失信了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아아, 진짜-","JPN":"ああ、もう～","ENG":"Ughhh…","TWN":"啊啊，真是的—"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"일어나면 흠씬 때려주려 했는데, 바로 반성해버리면 어쩌란 거냐고.","JPN":"起きたらぼこぼこにしてやるって決めてたのに、すぐ反省されたら怒る気にもなれないじゃん。","ENG":"I was ready to chew you out, but then you go and apologize right away. What am I supposed to do with that?","TWN":"我本來想等你醒來狠揍你一頓，結果你馬上就反省了，這讓我怎麼辦。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…뭐라도 먹을래?","JPN":"……何か食べる？","ENG":"…You hungry?","TWN":"…想吃點什麼嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이틀 내내 아무것도 안 먹고 누워만 있었잖아.","JPN":"2日間何も食べずに寝てたでしょ。","ENG":"You've been out for two days without a bite.","TWN":"你整整兩天沒吃東西了，只是一直躺著。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그 말을 들으니, 배가 고파오는군.","JPN":"その言葉を聞いたら急に腹が空いてきたな。","ENG":"Now that you mention it, I am a bit hungry.","TWN":"聽你這麼一說，我肚子餓了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"곶감이 먹고 싶어졌어.","JPN":"干し柿が食べたくなった。","ENG":"I'm craving dried persimmons.","TWN":"我想吃柿餅。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"곶감…? 뜬금없네.","JPN":"干し柿……？　また突然だね。","ENG":"Dried persimmons…? That's random.","TWN":"柿餅…？怎麼突然想吃這個。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"빈 속에 단 거 먹으면 탈 나. 계란찜이나 해줄게.","JPN":"胃に何もない状態で甘いもの食べたらお腹壊すよ。茶碗蒸し作ってあげる。","ENG":"You'll get a stomachache if you eat something that sweet on an empty stomach. I'll make you some steamed eggs.","TWN":"空腹吃甜食會對胃不好。我給你做蒸蛋吧。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"고맙네, 앤디.","JPN":"感謝する、アンディー。","ENG":"Thank you, Andy.","TWN":"謝謝你，安狄。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나 같이 별난 사람 곁을 계속 지켜주어서.","JPN":"某のような変わり者の側に、変わらず居てくれて。","ENG":"For sticking with someone as peculiar as me.","TWN":"一直守在我這個古怪的人身邊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"고마우면 죽을 짓 좀 골라서 하지 마.","JPN":"感謝してるなら死にそうな事ばっかりしないでよね。","ENG":"If you want to thank me, then don't make me watch you die.","TWN":"如果真的感謝我，就不要再選擇尋死的路。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"무덤 곁에까지 남아줄 생각은 없으니까.","JPN":"お墓に入った後まで側に居るつもりはないから。","ENG":"I'm not following you to your grave.","TWN":"我可沒有打算陪葬。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그건 당연한 걸세.","JPN":"それは当然だ。","ENG":"Of course.","TWN":"那當然。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"산 사람은 지난 과거보단 내일을 보고 살아야 하는 법이니까.","JPN":"生きている者は、過ぎた過去より明日を見て生きるべきだからな。","ENG":"The living should look toward tomorrow, not back at yesterday.","TWN":"活著的人，應該要向前看，而不是活在過去。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그렇게 말하는 사부는… 내일을 보면서 살고 있는 게 맞아?","JPN":"そういう師匠は……ちゃんと明日を見て生きてる？","ENG":"You say that… But are you really looking toward tomorrow?","TWN":"你說這話…自己有在向前看嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"맨날 과거로 돌아가는 거에만 집착하는 주제에.","JPN":"いつも過去に行くことしか考えてないくせに。","ENG":"You're always chasing the past.","TWN":"每天只顧著執著於回到過去。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"앤디.","JPN":"アンディー。","ENG":"Andy.","TWN":"安狄。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"내가 과거에 집착하는 건, 후회하는 내일을 되풀이하지 않기 위해서라네.","JPN":"某が過去にこだわるのは、後悔する明日を繰り返すまいと決めたからだ。","ENG":"I chase the past, so I don't repeat a regretful tomorrow.","TWN":"我之所以執著於過去，是因為不希望明天再後悔。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"정말로…","JPN":"……例えばさ……","ENG":"Seriously…","TWN":"如果真的…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"과거로 가서 그 연화 언니를 살린다고 치자.","JPN":"過去に戻ってレンカさんを救ったとしてだよ。","ENG":"Let's say you do go back and save Yeonhwa.","TWN":"回到過去救了蓮華姊姊。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"다음은 어떻게 할 건데?","JPN":"その後はどうするの？","ENG":"Then what?","TWN":"然後呢？你要做什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"꿈이 이뤄진 다음의 일은 그때 가서 생각해도 늦지 않겠지.","JPN":"夢が叶った後のことは、その時になって考えても遅くはなかろう。","ENG":"Once I achieve that, I'll worry about the rest then.","TWN":"夢想實現之後的事情，到時候再考慮也不遲。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"본래 두 수 앞을 내다볼 수 없는 것이 인생의 묘미 아니겠나?","JPN":"本来、すぐ先のことも分からないのが人生の醍醐味ではないか。","ENG":"Life's beauty lies in never knowing what comes two steps ahead.","TWN":"人生本來就無法預知下一步，這不是很有趣嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐야… 그게…","JPN":"何よ、それ……","ENG":"That's… well…","TWN":"什麼啊…你這話…"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"천재가 아니라 대책 없이 사는 바보나 할법한 말이네.","JPN":"バカみたい。天才の口から出た言葉とは思えないよ。","ENG":"Not something a genius says. Sounds more like what a clueless fool would, though.","TWN":"這話聽起來，不像天才，倒像是個得過且過的笨蛋。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"아, 어르신 연락 왔다.","JPN":"あ、おばあさんから連絡来た。","ENG":"Oh. Granny's calling.","TWN":"喔，阿姨打來了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"지수 양 말인가? 그러고 보니 지금 어디에 있지?","JPN":"シノ君か？　そういえばシノ君は今どこに？","ENG":"Jisoo? Where is she now?","TWN":"是智秀嗎？她現在在哪裡？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그때 사부가 빠졌던 우물 말이야. 멀쩡한지 살펴보러 갔거든.","JPN":"あの時師匠が落ちた井戸だよ。様子を見に行ったの。","ENG":"She went to check that well you fell into. Wanted to see if it's still intact.","TWN":"就是師父你掉下去的那個井，她去看看那裡有沒有事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};